export function getPandaStage(pct) {
  const n = Math.max(0, Math.min(100, Number(pct) || 0));
  return PANDA_STAGES.find((s) => n >= s.min && n <= s.max) || PANDA_STAGES[0];
}

let _sessionQuote = null;
export function pickMascotMessage() {
  if (_sessionQuote) return _sessionQuote;
  const i = Math.floor(Math.random() * MASCOT_MESSAGES.length);
  _sessionQuote = MASCOT_MESSAGES[i];
  return _sessionQuote;
}

export function refreshMascotMessage() {
  _sessionQuote = null;
  return pickMascotMessage();
}
